  console.error('Error: Base path is required');
  console.error('Usage: node rename-snake-to-camel.js <path> [--dry-run] [--apply] [--extensions=.js,.ts]');
  process.exit(1);
}

/**
 * Convert snake_case to camelCase
 */
function snakeToCamel(str) {
  return str.replace(/_([a-z])/g, (_, letter) => letter.toUpperCase());
}

/**
 * Check if a string is snake_case
 */
function isSnakeCase(str) {
  // Must contain at least one underscore, be all lowercase with underscores, and not start/end with underscore
  return /^[a-z][a-z0-9]*(_[a-z0-9]+)+$/.test(str);
}

/**
 * Recursively find all files with specified extensions
 */
async function findSourceFiles(dir, extensions) {
  const files = [];

  try {
    const entries = await fs.readdir(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);

      if (entry.isDirectory()) {
        // Skip node_modules and hidden directories
        if (entry.name === 'node_modules' || entry.name.startsWith('.')) {
          continue;
        }
        files.push(...(await findSourceFiles(fullPath, extensions)));
      } else if (entry.isFile()) {
        const ext = path.extname(entry.name);
        if (extensions.includes(ext)) {
          files.push(fullPath);
        }
      }
    }
  } catch (error) {
    console.error(`Error reading directory ${dir}:`, error.message);
  }

  return files;
}

/**
 * Find all snake_case identifiers in code and build a rename map
 * Uses regex-based approach to identify potential variable names
 */
function findSnakeCaseIdentifiers(content) {
  const identifierPattern = /\b[a-z][a-z0-9]*(_[a-z0-9]+)+\b/g;
  const identifiers = new Set();
  const matches = content.matchAll(identifierPattern);

  for (const match of matches) {
    const identifier = match[0];
    if (isSnakeCase(identifier)) {
      identifiers.add(identifier);
    }
  }

  return identifiers;
}

/**
 * Replace snake_case identifiers with camelCase versions
 * Uses word boundaries to avoid partial replacements
 */
function replaceIdentifiers(content, identifierMap) {
  let result = content;

  for (const [snakeCase, camelCase] of identifierMap.entries()) {
    // Use word boundaries to match whole identifiers only
    const regex = new RegExp(`\\b${snakeCase}\\b`, 'g');
    result = result.replace(regex, camelCase);
  }

  return result;
}

/**
 * Process a single file
 */
async function processFile(filePath) {
  try {
    const content = await fs.readFile(filePath, 'utf8');
    const snakeCaseIdentifiers = findSnakeCaseIdentifiers(content);

    if (snakeCaseIdentifiers.size === 0) {
      return { file: filePath, changes: 0, identifiers: [] };
    }

    // Build rename map
    const renameMap = new Map();
    for (const identifier of snakeCaseIdentifiers) {
      renameMap.set(identifier, snakeToCamel(identifier));
    }

    // Apply replacements
    const newContent = replaceIdentifiers(content, renameMap);

    // Write back if not dry run
    if (!dryRun && newContent !== content) {
      await fs.writeFile(filePath, newContent, 'utf8');
    }

    return {
      file: filePath,
      changes: renameMap.size,
      identifiers: Array.from(renameMap.entries()).map(([from, to]) => ({ from, to })),
    };
  } catch (error) {
    console.error(`Error processing ${filePath}:`, error.message);
    return { file: filePath, changes: 0, identifiers: [], error: error.message };
  }
}

/**
 * Main function
 */
async function main() {
  console.log(`Scanning for source files in: ${basePath}`);
  console.log(`Extensions: ${extensions.join(', ')}`);
  console.log(`Mode: ${dryRun ? 'DRY RUN (no changes will be applied)' : 'APPLY CHANGES'}\n`);

  // Verify base path exists
  try {
    await fs.access(basePath);
  } catch {
    console.error(`Error: Path does not exist: ${basePath}`);
    process.exit(1);
  }

  // Find all source files
  const files = await findSourceFiles(basePath, extensions);
  console.log(`Found ${files.length} source files\n`);

  // Process each file
  const results = [];
  for (const file of files) {
    const result = await processFile(file);
    if (result.changes > 0) {
      results.push(result);
    }
  }

  // Display results
  if (results.length === 0) {
    console.log('No snake_case identifiers found.');
  } else {
    console.log(`\nFound snake_case identifiers in ${results.length} file(s):\n`);

    for (const result of results) {
      const relativePath = path.relative(process.cwd(), result.file);
      console.log(`${relativePath}:`);
      for (const { from, to } of result.identifiers) {
        console.log(`  ${from} → ${to}`);
      }
      console.log();
    }

    const totalChanges = results.reduce((sum, r) => sum + r.changes, 0);
    console.log(`Total: ${totalChanges} identifier(s) in ${results.length} file(s)`);

    if (dryRun) {
      console.log('\n⚠️  DRY RUN: No changes were applied.');
      console.log('Run with --apply to make actual changes.');
    } else {
      console.log('\n✓ Changes applied successfully.');
    }
  }
}

main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});
